import { Component, EventEmitter, h, Listen, Prop, State, Event, Element } from '@stencil/core';
import type { FABMenuItemConfig } from '../wdpr-fab-menu-item/wdpr-fab-menu-item.model';
import type { FabTriggerSize } from './wdpr-fab-trigger/wdpr-fab-trigger';

@Component({
  tag: 'wdpr-fab',
  shadow: true,
})
export class WdprFab {
  @Element() el: HTMLElement;

  @State() open: boolean = false;
  @State() _focusedIndex: number = -1;

  @Prop() items: FABMenuItemConfig[] = [];
  @Prop() buttonLabel: string = 'Menu';
  @Prop() buttonIcon: string = 'all-activities';
  @Prop() backdropBlur: boolean = false;
  @Prop() size: FabTriggerSize = 'large';
  @Prop() disabled: boolean = false;

  @Event({ eventName: 'wdprItemClick' }) itemClickEvent: EventEmitter<FABMenuItemConfig>;

  @Listen('keydown', { target: 'window' })
  handleKeyDown(ev: KeyboardEvent) {
    if (!this.open) return;

    if (ev.key === 'Escape') {
      this._toggleMenu();

      return;
    }

    const menuItems = Array.from(this.el.shadowRoot.querySelectorAll('wdpr-fab-menu-item'));
    const trigger = this.el.shadowRoot.querySelector('wdpr-fab-trigger') as HTMLElement;

    if (menuItems.length === 0 || !trigger) return;
    const allElements = [...menuItems, trigger];

    if (["ArrowUp", "ArrowDown"].includes(ev.key)) {
      ev.preventDefault();
      const delta = ev.key === "ArrowUp" ? -1 : 1;
      let nextIndex = this._focusedIndex;
      let attempts = 0;
      do {
        nextIndex = (nextIndex + delta + allElements.length) % allElements.length;
        const el = allElements[nextIndex] as HTMLElement;
        const btn = el.shadowRoot?.querySelector("button");
        const isDisabled = btn?.hasAttribute("disabled") || btn?.getAttribute("aria-disabled") === "true";

        if (!isDisabled) break;
        attempts++;
      } while (attempts < allElements.length);

      this._focusedIndex = nextIndex;
      this._applyFocus(allElements[this._focusedIndex] as HTMLElement);
    }
  }

  private _applyFocus(el: HTMLElement) {
    if (!el) return;
    const button = el.shadowRoot?.querySelector('button');
    button?.focus();
  }

  private _toggleMenu = () => {
    this.open = !this.open;
    if (!this.open) {
      this._focusedIndex = -1;
      this.el.shadowRoot.querySelector('wdpr-fab-trigger')?.shadowRoot?.querySelector('button')?.focus();
    }
  };

  private _handleItemClick = (item: FABMenuItemConfig) => {
    this.open = false;
    this._focusedIndex = -1;
    this.itemClickEvent.emit(item);
  };

  private get _menuBottomClass(): string {
    return this.size === 'medium' ? 'bottom-18' : 'bottom-22';
  }

  render() {
    return (
      <div class="wdpr-fab-container">
        {this.open && (
          <div>
            <div
              class={`fixed w-full h-full inset-0 z-40 bg-(--color-plum-800-a60) opacity-60 ${this.backdropBlur ? 'backdrop-blur' : 'backdrop-blur-none'}`}
              onClick={this._toggleMenu}
              aria-hidden="true"
            ></div>

            <div
              class={`fixed ${this._menuBottomClass} right-6 z-50 flex flex-col items-end`}
              role="menu"
              part="menu"
            >
              {this.items.map((item, i) => (
                <wdpr-fab-menu-item key={item.id} item={item} isLast={i === this.items.length - 1} onWdprChange={e => this._handleItemClick(e.detail)} />
              ))}
            </div>
          </div>
        )}

        <div class="fixed bottom-6 right-6 z-50" part="trigger">
          <wdpr-fab-trigger open={this.open} size={this.size} label={this.buttonLabel} icon={this.buttonIcon} disabled={this.disabled} onWdprToggle={this._toggleMenu} />
        </div>
      </div>
    );
  }
}
